/**
 * 向量语义检索面板
 * 提供相似章节搜索功能
 *
 * 在 Electron 环境中，通过 IPC 调用 my-novel-tools 的 CLI 命令
 * 如果 CLI 不可用，则使用基于关键词的简单相似度搜索作为降级方案
 */

import { useState, useEffect } from 'react'
import {
  Input,
  Button,
  List,
  Card,
  Tag,
  Space,
  message,
  Alert,
  Spin,
  Tooltip,
  Modal,
} from 'antd'
import {
  SearchOutlined,
  BuildOutlined,
  CheckCircleOutlined,
  WarningOutlined,
} from '@ant-design/icons'

interface SearchResult {
  chapterPath: string
  chapterName: string
  similarity: number
  snippet: string
}

interface VectorSearchPanelProps {
  projectRoot: string | null
  onJumpToChapter?: (chapterPath: string) => void
}

const VectorSearchPanel: React.FC<VectorSearchPanelProps> = ({
  projectRoot,
  onJumpToChapter,
}) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [indexExists, setIndexExists] = useState<boolean | null>(null)
  const [cliAvailable, setCliAvailable] = useState<boolean | null>(null)

  // 检查向量索引是否存在
  const checkIndex = async () => {
    if (!projectRoot) return
    try {
      const indexFile = `${projectRoot}/data/vectors/index.json`
      const exists = await window.electronAPI.exists(indexFile)
      setIndexExists(exists)
    } catch {
      setIndexExists(false)
    }
  }

  useEffect(() => {
    checkIndex()
  }, [projectRoot])

  // 简单的关键词相似度搜索（降级方案）
  const simpleKeywordSearch = async (
    searchQuery: string,
    chapters: Array<{ path: string; name: string; content: string }>
  ): Promise<SearchResult[]> => {
    if (!searchQuery.trim()) return []

    const queryWords = searchQuery.toLowerCase().split(/\s+/).filter(Boolean)

    const scored = chapters.map(ch => {
      const content = ch.content.toLowerCase()
      let score = 0
      let matchedSnippet = ''

      // 计算关键词覆盖率
      const matchedWords = queryWords.filter(w => content.includes(w))
      score = matchedWords.length / queryWords.length

      // 找到匹配的片段
      const firstMatchIdx = content.indexOf(matchedWords[0] || queryWords[0])
      if (firstMatchIdx >= 0) {
        const start = Math.max(0, firstMatchIdx - 30)
        const end = Math.min(content.length, firstMatchIdx + 100)
        matchedSnippet = (start > 0 ? '...' : '') + ch.content.slice(start, end) + (end < content.length ? '...' : '')
      }

      return {
        chapterPath: ch.path,
        chapterName: ch.name,
        similarity: score,
        snippet: matchedSnippet || ch.content.slice(0, 100) + '...',
      }
    })

    return scored
      .filter(r => r.similarity > 0)
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 10)
  }

  // 加载所有章节内容
  const loadAllChapters = async (): Promise<Array<{ path: string; name: string; content: string }>> => {
    if (!projectRoot) return []

    const chapters: Array<{ path: string; name: string; content: string }> = []

    const readDir = async (dirPath: string) => {
      try {
        const entries = await window.electronAPI.readdir(dirPath)
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath)
          } else if (entry.isFile && entry.name.endsWith('.md')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const exists = await window.electronAPI.exists(plotsDir)
    if (exists) {
      await readDir(plotsDir)
    }

    return chapters
  }

  // 执行搜索
  const handleSearch = async () => {
    if (!query.trim()) {
      message.warning('请输入搜索内容')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    setLoading(true)
    setResults([])

    try {
      // 如果有向量索引，优先使用（通过 CLI 工具）
      if (indexExists) {
        // 由于浏览器无法直接运行 Node.js CLI，这里使用降级方案
        // 在实际 Electron 环境中，可以通过 IPC 调用主进程执行 CLI
        message.info('使用增强检索模式...')
      }

      // 使用关键词搜索作为降级方案
      const chapters = await loadAllChapters()
      const searchResults = await simpleKeywordSearch(query, chapters)
      setResults(searchResults)

      if (searchResults.length === 0) {
        message.info('未找到相关内容，尝试其他关键词')
      }
    } catch (error) {
      console.error('搜索失败:', error)
      message.error('搜索失败')
    } finally {
      setLoading(false)
    }
  }

  // 构建向量索引（提示用户使用 CLI）
  const handleBuildIndex = () => {
    Modal.info({
      title: '📦 构建向量索引',
      content: (
        <div>
          <p>向量索引构建需要在命令行中执行：</p>
          <pre
            style={{
              background: '#f5f5f5',
              padding: 12,
              borderRadius: 4,
              fontFamily: 'monospace',
              fontSize: 13,
            }}
          >{`cd my-novel-tools
node bin/build-vector-index.js -p ../your-project-path`}</pre>
          <p style={{ color: '#666', fontSize: 12 }}>
            首次运行会自动下载向量模型（约 130MB），请耐心等待。
          </p>
        </div>
      ),
      okText: '知道了',
      width: 500,
    })
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>🔍 相似章节检索</span>
        </div>

        {/* 索引状态 */}
        <div style={{ marginBottom: 10, fontSize: 12 }}>
          {indexExists ? (
            <Tag color="green" icon={<CheckCircleOutlined />}>
              向量索引已就绪
            </Tag>
          ) : (
            <Tag color="orange" icon={<WarningOutlined />}>
              未构建向量索引
            </Tag>
          )}
          <Button
            size="small"
            icon={<BuildOutlined />}
            onClick={handleBuildIndex}
            style={{ marginLeft: 8 }}
          >
            构建索引
          </Button>
        </div>

        {/* 搜索框 */}
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.Search
            placeholder="输入情节描述，查找相似章节..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onSearch={handleSearch}
            loading={loading}
            enterButton={
              <Button type="primary" icon={<SearchOutlined />}>
                搜索
              </Button>
            }
          />
        </Space>

        {!indexExists && (
          <Alert
            message="当前使用关键词匹配检索。构建向量索引后支持语义检索，效果更佳。"
            type="info"
            showIcon
            style={{ marginTop: 8, fontSize: 11 }}
          />
        )}
      </div>

      {/* 结果列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="搜索中..." />
          </div>
        ) : results.length === 0 ? (
          <div style={{ color: '#999', textAlign: 'center', padding: 40, fontSize: 13 }}>
            {query ? '未找到相似章节' : '输入内容开始搜索'}
          </div>
        ) : (
          <List
            dataSource={results}
            renderItem={(item) => (
              <List.Item
                style={{ cursor: 'pointer' }}
                onClick={() => onJumpToChapter?.(item.chapterPath)}
              >
                <List.Item.Meta
                  title={
                    <Space>
                      <span>{item.chapterName}</span>
                      <Tag color="blue">
                        相似度 {Math.round(item.similarity * 100)}%
                      </Tag>
                    </Space>
                  }
                  description={
                    <div
                      style={{
                        fontSize: 12,
                        color: '#666',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                      }}
                    >
                      {item.snippet}
                    </div>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </div>
    </div>
  )
}

export default VectorSearchPanel

/**
 * 世界设定页面
 * 显示世界观设定列表，支持新建、编辑、删除设定
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  List,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  SettingOutlined,
  CheckCircleOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import SettingDetail from './SettingDetail'
import aiModelService from '../services/aiModels'

interface WorldSetting {
  id: string
  name: string
  filePath: string
  summary?: string
  category?: string
}

interface SettingsPageProps {
  projectRoot: string | null
}

const SettingsPage: React.FC<SettingsPageProps> = ({ projectRoot }) => {
  const [settings, setSettings] = useState<WorldSetting[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedSetting, setSelectedSetting] = useState<WorldSetting | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)
  const [checkingConsistency, setCheckingConsistency] = useState(false)

  // 加载设定列表
  const loadSettings = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const settingsDir = `${projectRoot}/settings`
      const dirExists = await window.electronAPI.exists(settingsDir)
      if (!dirExists) {
        await window.electronAPI.mkdir(settingsDir)
        setSettings([])
        return
      }

      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedSettings: WorldSetting[] = []
      for (const file of settingFiles) {
        const filePath = `${settingsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          // 提取第一行作为摘要（去掉 # 注释）
          const rawContent = typeof data._raw === 'string'
            ? data._raw
            : ''
          loadedSettings.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            summary: typeof data.summary === 'string' ? data.summary : rawContent.slice(0, 100),
            category: data.category as string | undefined,
          })
        }
      }

      setSettings(loadedSettings)
    } catch (error) {
      console.error('加载设定失败:', error)
      message.error('加载设定列表失败')
    } finally {
      setLoading(false)
    }
  }

  // 新建设定
  const handleNewSetting = () => {
    setSelectedSetting(null)
    setDetailVisible(true)
  }

  // 编辑设定
  const handleEditSetting = (setting: WorldSetting) => {
    setSelectedSetting(setting)
    setDetailVisible(true)
  }

  // 删除设定
  const handleDeleteSetting = async (setting: WorldSetting) => {
    Modal.confirm({
      title: `确认删除设定「${setting.name}」？`,
      content: '删除后可通过备份恢复。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(setting.filePath)
          if (result.success) {
            message.success(`已删除设定「${setting.name}」`)
            loadSettings()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // AI 一致性检查
  const handleConsistencyCheck = async () => {
    if (!projectRoot) return
    setCheckingConsistency(true)
    try {
      // 收集所有设定文件内容
      const settingsDir = `${projectRoot}/settings`
      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      let allSettingsContent = ''
      for (const file of settingFiles) {
        const result = await window.electronAPI.yaml.read(`${settingsDir}/${file.name}`)
        if (result.success && result.data) {
          allSettingsContent += `\n### ${file.name.replace('.yaml', '')} ###\n`
          allSettingsContent += JSON.stringify(result.data, null, 2)
        }
      }

      if (!allSettingsContent.trim()) {
        message.warning('暂无设定可检查')
        return
      }

      const checkPrompt = `请检查以下世界设定内容，找出其中的矛盾点和不一致之处：

${allSettingsContent}

检查维度：
1. 战力体系是否矛盾（等级划分是否自洽）
2. 地理/空间设定是否冲突
3. 势力/门派设定是否矛盾
4. 时间线是否自洽
5. 能力设定是否有冲突

请列出发现的所有矛盾点，并给出修改建议。如果一切自洽，也请明确说明。`

      const result = await aiModelService.call(
        'logic',
        checkPrompt,
        {
          systemPrompt: '你是一个严格的世界观设定审核专家。请仔细检查设定的逻辑一致性。',
        }
      )

      if (result.success && result.content) {
        Modal.info({
          title: '🏛️ 世界观一致性检查结果',
          content: (
            <pre style={{
              maxHeight: 400,
              overflow: 'auto',
              whiteSpace: 'pre-wrap',
              fontSize: 13,
              fontFamily: 'monospace',
            }}>
              {result.content}
            </pre>
          ),
          width: 700,
          okText: '关闭',
        })
      } else {
        message.error(result.error || '检查失败')
      }
    } catch (error) {
      message.error('一致性检查失败')
    } finally {
      setCheckingConsistency(false)
    }
  }

  // 保存后刷新
  const handleSettingSaved = () => {
    setDetailVisible(false)
    loadSettings()
  }

  useEffect(() => {
    loadSettings()
  }, [projectRoot])

  // 过滤
  const filteredSettings = settings.filter(s =>
    s.name.toLowerCase().includes(searchText.toLowerCase())
  )

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: 10,
          }}
        >
          <h3 style={{ margin: 0 }}>世界观设定</h3>
          <Space>
            <Button
              icon={<CheckCircleOutlined />}
              onClick={handleConsistencyCheck}
              loading={checkingConsistency}
            >
              AI一致性检查
            </Button>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleNewSetting}
            >
              新建设定
            </Button>
          </Space>
        </div>
        <Input
          placeholder="搜索设定..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 设定列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredSettings.length === 0 ? (
          <Empty
            description={
              searchText
                ? '未找到匹配的设定'
                : '暂无设定，点击"新建设定"开始创建'
            }
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <List
            grid={{ gutter: 16, xs: 1, sm: 2, md: 3 }}
            dataSource={filteredSettings}
            renderItem={(item) => (
              <List.Item>
                <Card
                  hoverable
                  size="small"
                  actions={[
                    <EditOutlined
                      key="edit"
                      onClick={() => handleEditSetting(item)}
                    />,
                    <DeleteOutlined
                      key="delete"
                      onClick={() => handleDeleteSetting(item)}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                >
                  <Card.Meta
                    avatar={<SettingOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                    title={
                      <div>
                        {item.name}
                        {item.category && (
                          <Tag color="blue" style={{ marginLeft: 8, float: 'right' }}>
                            {item.category}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      item.summary && (
                        <div
                          style={{
                            fontSize: 12,
                            color: '#666',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            display: '-webkit-box',
                            WebkitLineClamp: 3,
                            WebkitBoxOrient: 'vertical',
                          }}
                        >
                          {item.summary}
                        </div>
                      )
                    }
                  />
                </Card>
              </List.Item>
            )}
          />
        )}
      </div>

      {/* 设定详情 Modal */}
      <SettingDetail
        visible={detailVisible}
        setting={selectedSetting}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleSettingSaved}
      />
    </div>
  )
}

export default SettingsPage

import { useState, useEffect, useRef } from 'react'
import { Layout, Menu, Button, message } from 'antd'
import {
  SaveOutlined,
  FolderOpenOutlined,
  BookOutlined,
  UserOutlined,
  SettingOutlined,
  ThunderboltOutlined,
  SearchOutlined,
} from '@ant-design/icons'
import OutlineTree from './OutlineTree'
import factsStore from '../db'
import Editor, { EditorHandle } from './Editor'
import FactsPanel from './FactsPanel'
import AIToolsPanel from './AIToolsPanel'
import CharactersPage from '../pages/CharactersPage'
import SettingsPage from '../pages/SettingsPage'
import AppSettingsPage from '../pages/AppSettingsPage'
import ProjectManager from './ProjectManager'
import VectorSearchPanel from './VectorSearchPanel'
import type { MenuProps } from 'antd'

const { Sider, Content } = Layout

type TabKey = 'outline' | 'characters' | 'world' | 'facts' | 'search' | 'appSettings'

// 左侧菜单
const siderMenuItems: MenuProps['items'] = [
  { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
  { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
  { key: 'world', icon: <SettingOutlined />, label: '世界设定' },
  { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
  { key: 'search', icon: <SearchOutlined />, label: '语义检索' },
  { key: 'appSettings', icon: <SettingOutlined />, label: '应用设置' },
]

const Workbench = () => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [activeChapter, setActiveChapter] = useState<string | null>(null)
  const [chapterContent, setChapterContent] = useState('')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [autoSaveTimer, setAutoSaveTimer] = useState<NodeJS.Timeout | null>(null)
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle')
  const [projectManagerVisible, setProjectManagerVisible] = useState(false)
  const editorRef = useRef<EditorHandle>(null)

  // 初始化项目
  useEffect(() => {
    const init = async () => {
      const root = await window.electronAPI.getProjectRoot()
      if (root) {
        setProjectRoot(root)
        factsStore.setProjectRoot(root)
      }
    }
    init()
  }, [])

  // 自动保存
  useEffect(() => {
    if (isDirty && activeChapter) {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)

      const timer = setTimeout(() => {
        handleSave()
      }, 5000) // 5秒防抖自动保存

      setAutoSaveTimer(timer)
    }

    return () => {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)
    }
  }, [chapterContent, isDirty])

  // 打开项目
  const handleOpenProject = () => {
    setProjectManagerVisible(true)
  }

  // 项目打开后的回调
  const handleProjectOpened = (projectPath: string) => {
    setProjectRoot(projectPath)
    factsStore.setProjectRoot(projectPath)
  }

  // 保存章节
  const handleSave = async () => {
    if (!activeChapter || !chapterContent) return

    setSaveStatus('saving')
    try {
      const result = await window.electronAPI.writeFile(activeChapter, chapterContent)
      if (result.success) {
        setIsDirty(false)
        setSaveStatus('saved')
        // 2秒后重置状态
        setTimeout(() => setSaveStatus('idle'), 2000)
      } else {
        setSaveStatus('error')
        message.error(`保存失败：${result.error}`)
        // 保存失败时立即重试一次
        setTimeout(async () => {
          setSaveStatus('saving')
          const retry = await window.electronAPI.writeFile(activeChapter, chapterContent)
          if (retry.success) {
            setIsDirty(false)
            setSaveStatus('saved')
            setTimeout(() => setSaveStatus('idle'), 2000)
          } else {
            setSaveStatus('error')
          }
        }, 1000)
      }
    } catch (error) {
      setSaveStatus('error')
      message.error('保存失败')
    }
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const confirm = window.confirm('当前章节有未保存的内容，是否保存？')
      if (confirm) await handleSave()
    }

    setActiveChapter(filePath)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
        setIsDirty(false)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={saveStatus === 'saving' || !activeChapter}
            loading={saveStatus === 'saving'}
          >
            {saveStatus === 'saving'
              ? '保存中...'
              : saveStatus === 'saved'
                ? '已保存 ✓'
                : saveStatus === 'error'
                  ? '保存失败 ↺'
                  : isDirty
                    ? '保存 *'
                    : '已保存'}
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && (
            <CharactersPage
              projectRoot={projectRoot}
              onCharacterClick={(name) => {
                // 可选：切换到大纲并搜索该角色相关内容
              }}
            />
          )}
          {activeTab === 'world' && (
            <SettingsPage projectRoot={projectRoot} />
          )}
          {activeTab === 'facts' && <FactsPanel />}
          {activeTab === 'search' && (
            <VectorSearchPanel
              projectRoot={projectRoot}
              onJumpToChapter={(path) => {
                handleChapterSelect(path)
              }}
            />
          )}
          {activeTab === 'appSettings' && <AppSettingsPage />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              ref={editorRef}
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <AIToolsPanel
            chapterContent={chapterContent}
            chapterPath={activeChapter}
            getSelectedText={() => editorRef.current?.getSelectedText() || ''}
            onInsertText={(text) => {
              // 支持 __REPLACE__ 标记：完全替换当前内容
              if (text.startsWith('__REPLACE__')) {
                const newContent = text.slice('__REPLACE__'.length)
                setChapterContent(newContent)
              } else {
                setChapterContent(prev => prev + text)
              }
              setIsDirty(true)
            }}
          />
        </Sider>
      </Layout>

      {/* 项目管理对话框 */}
      <ProjectManager
        visible={projectManagerVisible}
        onClose={() => setProjectManagerVisible(false)}
        onProjectOpened={handleProjectOpened}
      />
    </Layout>
  )
}

export default Workbench

/**
 * 导出管理器
 * 支持 Markdown 和 EPUB 格式导出
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Modal,
  Form,
  Select,
  Switch,
  message,
  Progress,
  Alert,
  Radio,
  Divider,
  List,
  Card,
  Tag,
  Input,
} from 'antd'
import {
  DownloadOutlined,
  FileMarkdownOutlined,
  BookOutlined,
  CheckCircleOutlined,
  FolderOpenOutlined,
} from '@ant-design/icons'

interface ExportManagerProps {
  projectRoot: string | null
  projectName?: string
  visible: boolean
  onClose: () => void
}

interface ChapterInfo {
  path: string
  name: string
  volume: string
  order: number
  content?: string
}

interface ExportProgress {
  current: number
  total: number
  status: 'idle' | 'exporting' | 'done' | 'error'
  message: string
}

const ExportManager: React.FC<ExportManagerProps> = ({
  projectRoot,
  projectName = '小说',
  visible,
  onClose,
}) => {
  const [exportFormat, setExportFormat] = useState<'markdown' | 'epub'>('markdown')
  const [exportMode, setExportMode] = useState<'single' | 'byVolume'>('single')
  const [includeToc, setIncludeToc] = useState(true)
  const [progress, setProgress] = useState<ExportProgress>({
    current: 0,
    total: 0,
    status: 'idle',
    message: '',
  })
  const [exportPath, setExportPath] = useState<string | null>(null)

  // 加载所有章节
  const loadChapters = async (): Promise<ChapterInfo[]> => {
    if (!projectRoot) return []

    const chapters: ChapterInfo[] = []

    const readDir = async (dirPath: string, volumeName: string = '正文') => {
      try {
        const entries = await window.electronAPI.readdir(dirPath)
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath, entry.name)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              // 提取章节序号
              const orderMatch = entry.name.match(/第(\d+)章/)
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                volume: volumeName,
                order: orderMatch ? parseInt(orderMatch[1]) : 0,
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const exists = await window.electronAPI.exists(plotsDir)
    if (exists) {
      await readDir(plotsDir)
    }

    return chapters.sort((a, b) => {
      if (a.volume !== b.volume) return a.volume.localeCompare(b.volume)
      return a.order - b.order
    })
  }

  // 导出 Markdown
  const exportMarkdown = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml 获取标题
      let title = projectName
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
        }
      } catch {}

      setProgress({ current: 0, total: chapters.length, status: 'exporting', message: '正在导出...' })

      if (exportMode === 'single') {
        // 单文件导出
        let toc = ''
        if (includeToc) {
          toc = `# ${title}\n\n`
          toc += `> 导出时间：${new Date().toLocaleString()}\n\n`
          toc += `## 目录\n\n`
          const volumes = [...new Set(chapters.map(c => c.volume))]
          for (const vol of volumes) {
            toc += `### ${vol}\n\n`
            const volChapters = chapters.filter(c => c.volume === vol)
            for (const ch of volChapters) {
              toc += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            toc += '\n'
          }
          toc += '---\n\n'
        }

        let fullContent = toc

        // 按卷分组
        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (const vol of volumes) {
          fullContent += `\n\n# ${vol}\n\n`
          const volChapters = chapters.filter(c => c.volume === vol)

          for (let i = 0; i < volChapters.length; i++) {
            const ch = volChapters[i]
            setProgress({
              current: i + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${ch.name}`,
            })

            fullContent += `\n\n## ${ch.name}\n\n`
            fullContent += ch.content || ''
          }
        }

        // 选择导出位置
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir) {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const exportFile = `${parentDir}/${title}.md`
        await window.electronAPI.writeFile(exportFile, fullContent)
        setExportPath(exportFile)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出到: ${exportFile}`)
      } else {
        // 按卷拆分导出
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir) {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (let vi = 0; vi < volumes.length; vi++) {
          const vol = volumes[vi]
          const volChapters = chapters.filter(c => c.volume === vol)

          let volContent = `# ${vol}\n\n`
          if (includeToc) {
            volContent += `## 目录\n\n`
            for (const ch of volChapters) {
              volContent += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            volContent += '\n---\n\n'
          }

          for (let ci = 0; ci < volChapters.length; ci++) {
            const ch = volChapters[ci]
            setProgress({
              current: vi * volChapters.length + ci + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${vol}/${ch.name}`,
            })

            volContent += `\n\n## ${ch.name}\n\n`
            volContent += ch.content || ''
          }

          const exportFile = `${parentDir}/${vol}.md`
          await window.electronAPI.writeFile(exportFile, volContent)
        }

        setExportPath(parentDir)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出 ${volumes.length} 个文件到: ${parentDir}`)
      }
    } catch (error) {
      message.error('导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 简单 HTML 转义
  const escapeHtml = (str: string): string => {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  // 转换为 EPUB XHTML
  const markdownToXhtml = (md: string, chapterTitle: string): string => {
    // 简单转换：处理标题和段落
    let html = md
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br/>')

    return `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <title>${escapeHtml(chapterTitle)}</title>
  <style>
    body { font-family: "SimSun", serif; font-size: 1em; line-height: 1.6; margin: 1em; }
    h1, h2, h3 { text-align: center; margin: 1em 0; }
    p { text-indent: 2em; margin: 0.5em 0; }
  </style>
</head>
<body>
  <h1>${escapeHtml(chapterTitle)}</h1>
  <p>${html}</p>
</body>
</html>`
  }

  // 生成 EPUB
  const exportEpub = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml
      let title = projectName
      let author = '未知作者'
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
          if (data.author) author = String(data.author)
        }
      } catch {}

      // 选择导出位置
      const parentDir = await window.electronAPI.openDirectory()
      if (!parentDir) {
        setProgress({ current: 0, total: 0, status: 'idle', message: '' })
        return
      }

      const safeTitle = title.replace(/[^\w\u4e00-\u9fa5]/g, '_')
      const epubDir = `${parentDir}/${safeTitle}_epub`
      await window.electronAPI.mkdir(`${epubDir}/META-INF`)
      await window.electronAPI.mkdir(`${epubDir}/OEBPS/chapters`)

      // mimetype（不压缩）
      await window.electronAPI.writeFile(`${epubDir}/mimetype`, 'application/epub+zip')

      // container.xml
      const container = `<?xml version="1.0" encoding="UTF-8"?>
<container version="1.0" xmlns="urn:oasis:names:tc:opendocument:xmlns:container">
  <rootfiles>
    <rootfile full-path="OEBPS/content.opf" media-type="application/oebps-package+xml"/>
  </rootfiles>
</container>`
      await window.electronAPI.writeFile(`${epubDir}/META-INF/container.xml`, container)

      // 生成 content.opf
      let spineItems = ''
      let manifestItems = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        manifestItems += `    <item id="ch${i + 1}" href="chapters/${chFileName}" media-type="application/xhtml+xml"/>\n`
        spineItems += `    <itemref idref="ch${i + 1}"/>\n`
      }

      const contentOpf = `<?xml version="1.0" encoding="UTF-8"?>
<package xmlns="http://www.idpf.org/2007/opf" unique-identifier="BookId" version="2.0">
  <metadata xmlns:dc="http://purl.org/dc/elements/1.1/">
    <dc:title>${escapeHtml(title)}</dc:title>
    <dc:creator>${escapeHtml(author)}</dc:creator>
    <dc:language>zh-CN</dc:language>
    <dc:identifier id="BookId">urn:uuid:${Date.now()}</dc:identifier>
  </metadata>
  <manifest>
    ${manifestItems}
    <item id="ncx" href="toc.ncx" media-type="application/x-dtbncx+xml"/>
    <item id="toc" href="toc.xhtml" media-type="application/xhtml+xml"/>
  </manifest>
  <spine toc="ncx">
${spiceItems}
  </spine>
</package>`
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/content.opf`, contentOpf)

      // 生成 toc.ncx
      let navPoints = ''
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        navPoints += `    <navPoint id="navpoint-${i + 1}" playOrder="${i + 1}">
      <navLabel><text>${escapeHtml(ch.name)}</text></navLabel>
      <content src="chapters/${chFileName}"/>
    </navPoint>\n`
      }

      const tocNcx = `<?xml version="1.0" encoding="UTF-8"?>
<ncx xmlns="http://www.dgipart.org/2007/ncx" version="2005-1">
  <head>
    <meta name="dtb:uid" content="urn:uuid:${Date.now()}"/>
    <meta name="dtb:depth" content="1"/>
    <meta name="dtb:totalPageCount" content="0"/>
    <meta name="dtb:maxPageNumber" content="0"/>
  </head>
  <docTitle><text>${escapeHtml(title)}</text></docTitle>
  <navMap>
${navPoints}
  </navMap>
</ncx>`
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.ncx`, tocNcx)

      // 生成章节内容
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        setProgress({
          current: i + 1,
          total: chapters.length,
          status: 'exporting',
          message: `正在处理: ${ch.name}`,
        })

        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        const xhtmlContent = markdownToXhtml(ch.content || '', ch.name)
        await window.electronAPI.writeFile(`${epubDir}/OEBPS/chapters/${chFileName}`, xhtmlContent)
      }

      // 生成 toc.xhtml (HTML目录)
      let tocHtml = `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head><title>目录</title></head>
<body>
<h1>目录</h1>
<nav xmlns="http://www.w3.org/1999/xhtml"><ol>`
      for (let i = 0; i < chapters.length; i++) {
        const ch = chapters[i]
        const chFileName = `chapter_${String(i + 1).padStart(3, '0')}.xhtml`
        tocHtml += `<li><a href="chapters/${chFileName}">${escapeHtml(ch.name)}</a></li>`
      }
      tocHtml += '</ol></nav></body></html>'
      await window.electronAPI.writeFile(`${epubDir}/OEBPS/toc.xhtml`, tocHtml)

      setExportPath(epubDir)
      setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: 'EPUB结构已生成' })
      message.success(`EPUB 文件结构已生成到: ${epubDir}\n请使用 epub 生成工具打包为 .epub 文件`)
    } catch (error) {
      message.error('EPUB 导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 执行导出
  const handleExport = async () => {
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    if (exportFormat === 'markdown') {
      await exportMarkdown()
    } else {
      await exportEpub()
    }
  }

  const handleOpenExport = () => {
    if (exportPath) {
      window.electronAPI.openPath(exportPath)
    }
  }

  return (
    <Modal
      title="📦 导出小说"
      open={visible}
      onCancel={onClose}
      width={500}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div>
        <Alert
          message="导出功能可以将您的章节内容导出为标准格式，便于在其他平台发布"
          type="info"
          showIcon
          style={{ marginBottom: 16 }}
        />

        <Form layout="vertical">
          <Form.Item label="导出格式">
            <Radio.Group
              value={exportFormat}
              onChange={(e) => setExportFormat(e.target.value)}
            >
              <Radio.Button value="markdown">
                <FileMarkdownOutlined /> Markdown
              </Radio.Button>
              <Radio.Button value="epub">
                <BookOutlined /> EPUB
              </Radio.Button>
            </Radio.Group>
          </Form.Item>

          <Form.Item label="导出模式">
            <Radio.Group
              value={exportMode}
              onChange={(e) => setExportMode(e.target.value)}
            >
              <Radio value="single">单文件</Radio>
